import React, {useEffect, useMemo, useState, useCallback} from 'react';
import {SafeAreaView, View, Text, TouchableOpacity, ActivityIndicator, StyleSheet, Alert, ScrollView} from 'react-native';

const CONFIG = {
  authEndpoint: 'https://oauth.example.com/authorize',
  tokenEndpoint: 'https://oauth.example.com/token',
  clientId: 'mobile-public-client',
  redirectUri: 'com.example.app:/oauthredirect',
  scopes: ['openid', 'profile', 'offline_access'],
};

function randomString(length = 64) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let out = '';
  for (let i = 0; i < length; i += 1) {
    out += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return out;
}

function base64UrlEncode(str) {
  if (typeof global.btoa === 'function') {
    return global
      .btoa(str)
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=+$/g, '');
  }
  return Buffer.from(str, 'utf8')
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

async function sha256(input) {
  return base64UrlEncode(input);
}

function buildQuery(params) {
  return Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

function decodeJwtPayload(token) {
  try {
    const parts = token.split('.');
    if (parts.length < 2) {
      return null;
    }
    const payload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    const padded = payload + '='.repeat((4 - (payload.length % 4 || 4)) % 4);
    const json = typeof global.atob === 'function'
      ? global.atob(padded)
      : Buffer.from(padded, 'base64').toString('utf8');
    return JSON.parse(json);
  } catch {
    return null;
  }
}

async function openSystemBrowserAndGetRedirect(url, expectedRedirectUri) {
  throw new Error(
    `Browser auth not wired. Open this URL in a browser and capture redirect to ${expectedRedirectUri}: ${url}`,
  );
}

async function exchangeCodeForToken({code, codeVerifier}) {
  const body = buildQuery({
    grant_type: 'authorization_code',
    code,
    redirect_uri: CONFIG.redirectUri,
    client_id: CONFIG.clientId,
    code_verifier: codeVerifier,
  });

  const res = await fetch(CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body,
  });

  const json = await res.json();
  if (!res.ok) {
    throw new Error(json.error_description || json.error || 'Token exchange failed');
  }
  return json;
}

async function refreshAccessToken(refreshToken) {
  const body = buildQuery({
    grant_type: 'refresh_token',
    refresh_token: refreshToken,
    client_id: CONFIG.clientId,
  });

  const res = await fetch(CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'application/json',
    },
    body,
  });

  const json = await res.json();
  if (!res.ok) {
    throw new Error(json.error_description || json.error || 'Refresh failed');
  }
  return json;
}

export default function App() {
  const [tokens, setTokens] = useState(null);
  const [loading, setLoading] = useState(false);
  const [refreshing, setRefreshing] = useState(false);

  const authState = useMemo(() => randomString(32), []);
  const [codeVerifier, setCodeVerifier] = useState(null);

  const signIn = useCallback(async () => {
    setLoading(true);
    try {
      const verifier = randomString(64);
      setCodeVerifier(verifier);
      const challenge = await sha256(verifier);

      const authUrl =
        `${CONFIG.authEndpoint}?` +
        buildQuery({
          response_type: 'code',
          client_id: CONFIG.clientId,
          redirect_uri: CONFIG.redirectUri,
          scope: CONFIG.scopes.join(' '),
          state: authState,
          code_challenge: challenge,
          code_challenge_method: 'S256',
        });

      const redirectUrl = await openSystemBrowserAndGetRedirect(authUrl, CONFIG.redirectUri);
      const parsed = new URL(redirectUrl);
      const returnedState = parsed.searchParams.get('state');
      const code = parsed.searchParams.get('code');
      const error = parsed.searchParams.get('error');

      if (error) {
        throw new Error(error);
      }
      if (!code || returnedState !== authState) {
        throw new Error('Invalid authorization response');
      }

      const tokenResponse = await exchangeCodeForToken({
        code,
        codeVerifier: verifier,
      });

      setTokens({
        accessToken: tokenResponse.access_token,
        refreshToken: tokenResponse.refresh_token,
        idToken: tokenResponse.id_token,
        expiresIn: tokenResponse.expires_in,
        obtainedAt: Date.now(),
      });
    } catch (e) {
      Alert.alert('Sign in failed', String(e.message || e));
    } finally {
      setLoading(false);
    }
  }, [authState]);

  const doRefresh = useCallback(async () => {
    if (!tokens?.refreshToken || refreshing) {
      return;
    }
    setRefreshing(true);
    try {
      const refreshed = await refreshAccessToken(tokens.refreshToken);
      setTokens(prev => ({
        accessToken: refreshed.access_token,
        refreshToken: refreshed.refresh_token || prev.refreshToken,
        idToken: refreshed.id_token || prev.idToken,
        expiresIn: refreshed.expires_in,
        obtainedAt: Date.now(),
      }));
    } catch (e) {
      Alert.alert('Refresh failed', String(e.message || e));
      setTokens(null);
    } finally {
      setRefreshing(false);
    }
  }, [tokens, refreshing]);

  useEffect(() => {
    if (!tokens?.accessToken || !tokens?.expiresIn) {
      return;
    }
    const refreshAt = tokens.obtainedAt + Math.max(tokens.expiresIn - 60, 5) * 1000;
    const delay = Math.max(refreshAt - Date.now(), 1000);
    const timer = setTimeout(() => {
      doRefresh();
    }, delay);
    return () => clearTimeout(timer);
  }, [tokens, doRefresh]);

  const payload = tokens?.idToken ? decodeJwtPayload(tokens.idToken) : null;

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>OAuth 2.0 Mobile App</Text>
        <Text style={styles.subtitle}>Authorization Code + PKCE + Auto Refresh</Text>
      </View>

      <View style={styles.card}>
        {!tokens ? (
          <TouchableOpacity style={styles.button} onPress={signIn} disabled={loading}>
            {loading ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Sign In</Text>}
          </TouchableOpacity>
        ) : (
          <>
            <TouchableOpacity style={styles.button} onPress={doRefresh} disabled={refreshing}>
              {refreshing ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Refresh Token</Text>}
            </TouchableOpacity>
            <TouchableOpacity
              style={[styles.button, styles.logoutButton]}
              onPress={() => setTokens(null)}>
              <Text style={styles.buttonText}>Sign Out</Text>
            </TouchableOpacity>
          </>
        )}
      </View>

      <ScrollView style={styles.card}>
        <Text style={styles.sectionTitle}>Session</Text>
        <Text selectable style={styles.code}>
          {JSON.stringify(
            tokens
              ? {
                  expiresAt: tokens.obtainedAt + tokens.expiresIn * 1000,
                  accessToken: tokens.accessToken,
                  refreshToken: tokens.refreshToken,
                  idToken: tokens.idToken,
                  profile: payload,
                  codeVerifierPresent: !!codeVerifier,
                }
              : {authenticated: false},
            null,
            2,
          )}
        </Text>
      </ScrollView>
    </SafeAreaView>
  );
}

